import hashlib

def calculate_file_hash(file_path):
    try:
        with open(file_path, 'rb') as f:
            hash_object = hashlib.sha256(f.read())
            return hash_object.hexdigest()
    except Exception as e:
        print(f"Error calculating file hash: {e}")
        return None